const body = $input.first().json;
const values = Array.isArray(body.value) ? body.value : [];
const projectCode = $json.body?.project_code || null;

const evidence = values.map((item, index) => {
  const sourceUri = item.webUrl || ('https://graph.microsoft.com/v1.0/drives/' + item.parentReference?.driveId + '/items/' + item.id);
  const excerpt = (item.description || item.name || '').toString().substring(0, 1000);
  let hash;
  try {
    const crypto = require('crypto');
    hash = crypto.createHash('sha256').update(JSON.stringify(item)).digest('hex');
  } catch (e) {
    hash = 'sp-' + (item.id || index) + '-' + (item.lastModifiedDateTime || 'unknown');
  }
  return {
    evidence_id: 'sp-' + (item.id || index),
    source_type: 'sharepoint',
    source_uri: sourceUri,
    title: item.name || 'Untitled',
    project_code: projectCode,
    contract_no: $json.body?.contract_no || null,
    revision: item.etag ? item.etag.replace(/["]/g, '') : null,
    timestamp: item.lastModifiedDateTime || null,
    excerpt: excerpt,
    hash_sha256: hash,
    confidence: 'medium',
    tags: ['sharepoint', 'document'],
    metadata: {
      drive_id: item.parentReference?.driveId || null,
      item_id: item.id || null,
      created_by: item.createdBy?.user?.displayName || null
    }
  };
});

return [{ json: { evidence: evidence } }];
